const cfg = $input.item.json;

const SHIPSEN_BASE = "https://api.shipsen.com";
const SUPABASE_URL = cfg.supabase_url;
const SUPABASE_SERVICE_ROLE_KEY = cfg.supabase_service_role_key;
const LIMIT = 100;
const UPSERT_BATCH_SIZE = 500;
const MIN_ORDER_DATE = "2025-07-01"; // plancher demandé par le CEO — pas de borne haute, on synchronise jusqu'à aujourd'hui
const TOKEN_MAX_AGE_MS = 4 * 60 * 1000; // re-login défensif si un cycle traîne

// Un seul compte Shipsen (email/mot de passe) donne accès aux 4 warehouses.
const WAREHOUSES = [
  { country: "Mali", currency: "XOF", warehouse: "619ff174286e83d6aa8f60ba" },
  { country: "Guinea", currency: "GNF", warehouse: "61ceeaa3d08e37d6dca5f6b9" },
  { country: "Senegal", currency: "XOF", warehouse: "61cee91cd08e37d6dca5e4fb" },
  { country: "CoteIvoire", currency: "XOF", warehouse: "619ed4e22c5c08be6fcfd977" },
];

function findHeader(headers, name) {
  const key = Object.keys(headers || {}).find((k) => k.toLowerCase() === name.toLowerCase());
  return key ? headers[key] : undefined;
}

function bodyPreview(body) {
  try {
    return JSON.stringify(body).slice(0, 500);
  } catch {
    return String(body).slice(0, 500);
  }
}

// On utilise returnFullResponse + ignoreHttpStatusErrors partout : ça permet de lire
// le corps de la réponse MÊME quand le statut HTTP est une erreur, pour savoir
// précisément pourquoi (au lieu d'un AxiosError générique sans détail exploitable).
async function shipsenLogin() {
  const res = await this.helpers.httpRequest({
    method: "POST",
    url: `${SHIPSEN_BASE}/users/login`,
    headers: { "Content-Type": "application/json;charset=utf-8" },
    body: { email: cfg.shipsen_email, password: cfg.shipsen_password },
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

  if (res.statusCode < 200 || res.statusCode >= 300) {
    throw new Error(`POST /users/login → HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
  }

  // Particularité Shipsen : ce n'est PAS un header HTTP réel — le corps JSON de
  // la réponse contient lui-même un champ imbriqué "headers" qui porte le token
  // (contrairement à ClickMarket où le token est à la racine du corps).
  const token = findHeader(res.body && res.body.headers, "X-Auth-Token");
  if (!token) {
    throw new Error(`POST /users/login → 200 mais pas de headers.X-Auth-Token: ${bodyPreview(res.body)}`);
  }
  return token;
}

const allRows = [];
const errors = [];
const perWarehouse = [];

if (!cfg.shipsen_email || !cfg.shipsen_password) {
  errors.push({ country: "ALL", message: "shipsen_email / shipsen_password manquants dans le nœud 'Config'." });
} else {
  let token = null;
  let tokenIssuedAt = 0;

  // ─── 1. Login — un seul token pour les 4 warehouses ──────────────────────
  try {
    token = await shipsenLogin.call(this);
    tokenIssuedAt = Date.now();
  } catch (err) {
    errors.push({ country: "ALL", message: `Login initial échoué — ${err.message}` });
  }

  // ─── 2. Pour chaque warehouse, paginer /orders/search jusqu'à la dernière page ───
  if (token) {
    for (const wh of WAREHOUSES) {
      let fetched = 0;
      let apiTotal = null;

      try {
        let page = 1;
        let lastPage = 1;

        do {
          // Re-login défensif si la pagination cumulée dépasse ~4 min.
          if (Date.now() - tokenIssuedAt > TOKEN_MAX_AGE_MS) {
            token = await shipsenLogin.call(this);
            tokenIssuedAt = Date.now();
          }

          const res = await this.helpers.httpRequest({
            method: "GET",
            url: `${SHIPSEN_BASE}/shippings/search`,
            qs: { warehouse: wh.warehouse, limit: LIMIT, page },
            headers: { "X-Auth-Token": token },
            json: true,
            returnFullResponse: true,
            ignoreHttpStatusErrors: true,
          });

          if (res.statusCode < 200 || res.statusCode >= 300) {
            throw new Error(`GET /shippings/search (page ${page}) → HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
          }

          const content = (res.body && res.body.content) || {};
          lastPage = content.last_page ?? 1;
          if (apiTotal === null) apiTotal = content.total ?? null;

          for (const o of content.results || []) {
            // Réponse /shippings/search : l'order complet vit sous o.order (o est le SHIPPING,
            // avec son propre statut/dates de livraison — distincts de ceux de l'order).
            const order = o.order || {};
            const firstItem =
              Array.isArray(order.details) && order.details.length > 0 ? order.details[0] : null;
            // order.date, pas order.createdAt (2026-07-14) : createdAt s'est avéré identique sur
            // plusieurs commandes différentes dans un échantillon audité en direct (probable
            // timestamp d'import en lot, pas la date réelle par commande) — order.date varie
            // correctement par commande. Même correction côté shipsen-leads-sync.workflow.json.
            const orderDateIso = order.date ?? order.createdAt ?? null;
            const orderDate = orderDateIso ? String(orderDateIso).slice(0, 10) : null;
            if (!orderDate || orderDate < MIN_ORDER_DATE) continue;

            allRows.push({
              order_id: order.id ?? order._id ?? o._id,
              mongo_id: o._id,
              // On utilise wh.country/wh.currency (notre config), pas o.warehouse (un simple id
              // Mongo côté /shippings/search, sans info pays/devise) — inutile de le résoudre
              // puisqu'on sait déjà, par warehouse, à quel pays on a affaire.
              country: wh.country,
              currency: wh.currency,
              warehouse_id: o.warehouse ?? wh.warehouse,
              customer_name: order.customer?.fullName ?? null,
              customer_phone: order.customer?.phoneNormalized ?? order.customer?.phone ?? null,
              product_name: firstItem?.productName ?? null,
              quantity: firstItem?.quantity ?? null,
              unit_price: firstItem?.unitPrice ?? null,
              total_price: order.totalPrice ?? 0,
              status: o.status ?? "unknown",
              is_processed: !!o.isProcessed,
              is_refunded: !!o.isRefunded,
              source: order.source ?? null,
              tracking_number: o.trackingNumber ?? null,
              shipping_date: o.date ? String(o.date).slice(0, 10) : null,
              order_date: orderDateIso,
              created_at: o.createdAt ?? null,
              updated_at: o.updatedAt ?? null,
              paid_at: o.paidAt ?? null,
              processed_at: o.processedAt ?? null,
            });
            fetched += 1;
          }

          page += 1;
        } while (page <= lastPage);
      } catch (err) {
        // Une erreur sur un warehouse ne doit pas empêcher les 3 autres d'être synchronisés.
        errors.push({ country: wh.country, message: err.message });
      }

      // Visible même sans erreur HTTP : si apiTotal vaut 0 (ou fetched reste à 0 alors
      // qu'apiTotal > 0), ça pointe vers un problème d'accès/ID de warehouse plutôt
      // qu'un bug de code — un 200 OK avec une liste vide ne lève jamais d'exception.
      perWarehouse.push({ country: wh.country, warehouse: wh.warehouse, apiTotal, fetched });
    }
  }
}

// ─── 3. Upsert en masse vers Supabase, par lots de 500 lignes ─────────────
// Dédup par mongo_id d'abord : si la pagination Shipsen chevauche deux pages
// (données qui bougent pendant la synchro), on ne veut pas que la même ligne
// apparaisse deux fois dans un même lot (Postgres refuse "ON CONFLICT DO UPDATE
// ... affect row a second time" dans ce cas). On garde la dernière occurrence.
const dedupedRows = Array.from(new Map(allRows.map((r) => [r.mongo_id, r])).values());

let upserted = 0;

// Chaque lot est essayé indépendamment : si un lot échoue, on continue quand
// même avec les suivants au lieu d'abandonner tout le reste de la synchro.
for (let i = 0; i < dedupedRows.length; i += UPSERT_BATCH_SIZE) {
  const batch = dedupedRows.slice(i, i + UPSERT_BATCH_SIZE);

  try {
    const res = await this.helpers.httpRequest({
      method: "POST",
      url: `${SUPABASE_URL}/rest/v1/shipsen_orders`,
      headers: {
        "Content-Type": "application/json",
        apikey: SUPABASE_SERVICE_ROLE_KEY,
        Authorization: `Bearer ${SUPABASE_SERVICE_ROLE_KEY}`,
        Prefer: "resolution=merge-duplicates,return=minimal",
      },
      body: batch,
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });

    if (res.statusCode < 200 || res.statusCode >= 300) {
      throw new Error(`HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
    }

    upserted += batch.length;
  } catch (err) {
    errors.push({ country: "SUPABASE_UPSERT", message: `lot ${i}-${i + batch.length}: ${err.message}` });
  }
}

return [
  {
    json: {
      synced_orders: upserted,
      warehouses: WAREHOUSES.map((w) => w.country),
      perWarehouse,
      errors,
      finished_at: new Date().toISOString(),
    },
  },
];
